+    ResizeIntent {
+        pane_id,
+        intent_seq,
+        scheduler_class: ResizeWorkClass::Interactive,
+        work_units: 1,
+        submitted_at_ms,
+        domain: ResizeDomain::Local,
+        tab_id: Some(1),
+    }
+}
